     1→export function renderMarkdown(md: string): string {
     2→  if (!md) return "";
     3→
     4→  let html = md
     5→    // Escape HTML
     6→    .replace(/&/g, "&amp;")
     7→    .replace(/</g, "&lt;")
     8→    .replace(/>/g, "&gt;");
     9→
    10→  // Code blocks
    11→  html = html.replace(/```[\w]*\n([\s\S]*?)```/g, (_, code) =>
    12→    `<pre><code>${code.trim()}</code></pre>`
    13→  );
    14→
    15→  // Inline code
    16→  html = html.replace(/`([^`]+)`/g, "<code>$1</code>");
    17→
    18→  // Headings
    19→  html = html.replace(/^#### (.+)$/gm, "<h4>$1</h4>");
    20→  html = html.replace(/^### (.+)$/gm, "<h3>$1</h3>");
    21→  html = html.replace(/^## (.+)$/gm, "<h2>$1</h2>");
    22→  html = html.replace(/^# (.+)$/gm, "<h1>$1</h1>");
    23→
    24→  // Bold + italic
    25→  html = html.replace(/\*\*\*(.+?)\*\*\*/g, "<strong><em>$1</em></strong>");
    26→  // Bold
    27→  html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
    28→  // Italic
    29→  html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");
    30→
    31→  // Links
    32→  html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>');
    33→
    34→  // Horizontal rule
    35→  html = html.replace(/^---$/gm, "<hr />");
    36→
    37→  // Blockquote
    38→  html = html.replace(/^> (.+)$/gm, "<blockquote>$1</blockquote>");
    39→
    40→  // Unordered list
    41→  html = html.replace(/(^[\-\*] .+(\n|$))+/gm, (block) => {
    42→    const items = block.trim().split("\n").map((line) =>
    43→      `<li>${line.replace(/^[\-\*] /, "")}</li>`
    44→    ).join("");
    45→    return `<ul>${items}</ul>`;
    46→  });
    47→
    48→  // Ordered list
    49→  html = html.replace(/(^\d+\. .+(\n|$))+/gm, (block) => {
    50→    const items = block.trim().split("\n").map((line) =>
    51→      `<li>${line.replace(/^\d+\. /, "")}</li>`
    52→    ).join("");
    53→    return `<ol>${items}</ol>`;
    54→  });
    55→
    56→  // Paragraphs (lines not already inside block elements)
    57→  html = html
    58→    .split(/\n{2,}/)
    59→    .map((block) => {
    60→      const trimmed = block.trim();
    61→      if (!trimmed) return "";
    62→      if (/^<(h[1-6]|ul|ol|li|pre|blockquote|hr)/.test(trimmed)) return trimmed;
    63→      return `<p>${trimmed.replace(/\n/g, "<br />")}</p>`;
    64→    })
    65→    .join("\n");
    66→
    67→  return html;
    68→}
