                <TableCell><button type="button" onClick={() => onChange({ ...settings, roiExamples: exs.filter((_, j) => j !== i) })} className="text-slate-400 hover:text-red-500 transition-colors"><X size={14} /></button></TableCell>
              </TableRow>
            ))}
